let input = '';
    let terminalOpen = false;
    let ctrlPressed = false;
    let shiftPressed = false;

    const display = document.getElementById('display');
    const terminal = document.getElementById('terminal');
    const ctrlKey = document.getElementById('ctrlKey');
    const shiftKey = document.getElementById('shiftKey');

    const moneyEmojis = ['💰', '💵', '💴', '💶', '💷', '💸', '🤑', '💲', '🪙'];

    function updateDisplay() {
      display.textContent = input;
    }

    function openTerminal() {
      if (!terminalOpen) {
        terminalOpen = true;
        terminal.classList.add('active');
        input = '';
        updateDisplay();
      }
    }

    function spawnMoney() {
      for (let i = 0; i < 30; i++) {
        setTimeout(() => {
          const emoji = document.createElement('div');
          emoji.className = 'money-emoji';
          emoji.textContent = moneyEmojis[Math.floor(Math.random() * moneyEmojis.length)];
          emoji.style.left = Math.random() * 100 + '%';
          emoji.style.top = -50 + 'px';
          emoji.style.animationDuration = (1.5 + Math.random()) + 's';
          document.body.appendChild(emoji);

          setTimeout(() => emoji.remove(), 2500);
        }, i * 100);
      }
    }

    function checkMotherlode() {
      if (input.toUpperCase() === 'MOTHERLODE') {
        spawnMoney();
        input = '';
        updateDisplay();
      }
    }

    function handleKey(key) {
      if (!terminalOpen) return;

      if (key === 'Backspace') {
        input = input.slice(0, -1);
      } else if (key === 'Enter') {
        checkMotherlode();
      } else if (key === ' ') {
        input += ' ';
      } else if (key === 'Control' || key === 'Shift') {
        return;
      } else if (key.length === 1) {
        input += key.toUpperCase();
      }
      updateDisplay();
    }

    document.querySelectorAll('kbd').forEach(key => {
      key.addEventListener('click', () => {
        const keyValue = key.getAttribute('data-key');

        if (keyValue === 'Control') {
          ctrlPressed = !ctrlPressed;
          key.classList.toggle('pressed', ctrlPressed);
          return;
        }

        if (keyValue === 'Shift') {
          shiftPressed = !shiftPressed;
          key.classList.toggle('pressed', shiftPressed);
          return;
        }

        if (ctrlPressed && shiftPressed && keyValue === 'C') {
          openTerminal();
          ctrlPressed = false;
          shiftPressed = false;
          ctrlKey.classList.remove('pressed');
          shiftKey.classList.remove('pressed');
        }

        handleKey(keyValue);
        key.classList.add('pressed');
        setTimeout(() => {
          if (keyValue !== 'Control' && keyValue !== 'Shift') {
            key.classList.remove('pressed');
          }
        }, 150);
      });
    });

    document.addEventListener('keydown', (e) => {
      if (e.key === 'Control') {
        ctrlPressed = true;
        ctrlKey.classList.add('pressed');
      }
      if (e.key === 'Shift') {
        shiftPressed = true;
        shiftKey.classList.add('pressed');
      }

      if (ctrlPressed && shiftPressed && e.key.toLowerCase() === 'c') {
        e.preventDefault();
        openTerminal();
        return;
      }

      if (!terminalOpen) return;

      const key = e.key;
      if (key === 'Backspace' || key === 'Enter' || key === ' ' || /^[a-zA-Z]$/.test(key)) {
        e.preventDefault();
        handleKey(key);

        const kbd = document.querySelector(`kbd[data-key="${key.toUpperCase()}"]`) ||
                    document.querySelector(`kbd[data-key="${key}"]`);
        if (kbd) {
          kbd.classList.add('pressed');
          setTimeout(() => kbd.classList.remove('pressed'), 150);
        }
      }
    });

    document.addEventListener('keyup', (e) => {
      if (e.key === 'Control') {
        ctrlPressed = false;
        ctrlKey.classList.remove('pressed');
      }
      if (e.key === 'Shift') {
        shiftPressed = false;
        shiftKey.classList.remove('pressed');
      }
    });

style.css:
@import url('https://fonts.googleapis.com/css2?family=DotGothic16&family=Google+Sans:ital,opsz,wght@0,17..18,400..700;1,17..18,400..700&family=Kalam:wght@300;400;700&display=swap');

:root {
      --bg: #fffcf2;
      --gr0: #B2A795;
      --gr1: #CCC5B9;
      --gr2: #403D39;
      --dark: #151513;
      --accent: #EB5E28;
    }

body {
	height: 100vh;
	margin: 0;
	display: grid;
	place-items: center;
	background: var(--bg);
	overflow: hidden;
}

body::before {
	content: "";
	position: fixed;
	inset: 0;
	background-image: url("https://images.pexels.com/photos/380769/pexels-photo-380769.jpeg");
	background-size: cover;
	background-position: center;
	filter: blur(6.5px);
	transform: scale(1.05);
	z-index: -1;
}

.sticky-note {
	background-color: var(--accent);
	color: var(--dark);
	font-family: "Kalam", cursive;
	font-weight: 300;
	font-style: normal;
	padding: 1.5rem;
	width: 10rem;
	min-height: 10rem;
	box-shadow: 2px 2px 8px var(--gr2);
	transform: rotate(-3deg);
	position: absolute;
	top: 10%;
	left: 5%;
	font-size: 1rem;
	line-height: 1.6;
	z-index: -1;
}

.space {
	flex-grow: 1/5;
	min-width: 9rem;
}

kbd {
	background-color: var(--bg);
	color: var(--dark);
	border-radius: 0.25rem;
	border: 1px solid var(--gr1);
	box-shadow: 0 2px 0 1px var(--gr1);
	cursor: default;
	font-family: "Google Sans", sans-serif;
	font-optical-sizing: auto;
	font-weight: 400;
	font-style: normal;
	font-variation-settings: "GRAD" 0;
	font-size: 0.75rem;
	line-height: 1;
	min-width: 0.25rem;
	display: inline-block;
	text-align: center;
	padding: 0.5rem 1rem;
	position: relative;
	top: -1px;
	user-select: none;
	transition: all 0.05s;
    }

kbd:hover {
	box-shadow: 0 2px 0 1px var(--gr2);
	background: var(--gr1);
	top: 1px;
	cursor: pointer;
}

kbd.pressed {
	box-shadow: 0 1px 0 0.5px var(--gr2);
	background: var(--gr1);
	top: 1px;
}

.controls {
	background: var(--gr0);
}

.keyboard {
	display: grid;
	gap: 0.5rem;
	background: var(--dark);
	margin: auto;
	padding: 1rem; 
	border-radius: 0.25rem;
	border: 2px solid var(--gr2);
	box-shadow: 0 4px 0 2px var(--gr2);
	bottom: -20%;
}

.keyboard-row {
	display: flex;
	justify-content: center;
	gap: 6px;
	flex-wrap: wrap;
}

@media (max-width: 600px) {
	.kbd {
		padding: 0.5rem 0.5rem;
	}	
}

.terminal-window {
	background: var(--bg);
	border: 2px solid var(--gr1);
	padding: 1rem;
	margin-top: auto;
	text-align: left;
	min-height: 7rem;
	min-width: 20rem;
	box-shadow: 0 4px 0 2px var(--gr1);
	border-radius: 0.25rem;
	display: none;
}

.terminal-window.active {
	display: block;
	animation: slideDown 0.3s ease-out;
}

@keyframes slideDown {
	from {
		opacity: 0;
		transform: translateY(-20px);
	}
	to {
		opacity: 1;
		transform: translateY(0);
	}
}

.terminal-prompt {
	font-family: "DotGothic16", sans-serif;
	font-weight: 400;
	font-style: normal;
	color: var(--dark);
	font-size: clamp(0.9rem, 2.5vw, 1.1rem);
    }

.terminal-input {
	font-family: "DotGothic16", sans-serif;
	font-weight: 400;
	font-style: normal;
	color: var(--dark);
	font-size: clamp(0.9rem, 2.5vw, 1.1rem);
	letter-spacing: 2px;
}

.cursor {
	display: inline-block;
	width: 10px;
	height: 1.2em;
	background: var(--dark);
	animation: blink 1s step-end infinite;
	margin-left: 2px;
	}

@keyframes blink {
	0%, 50% { opacity: 1; }
	51%, 100% { opacity: 0; }
}

.money-emoji {
	position: fixed;
	font-size: 3rem;
	pointer-events: none;
	z-index: 9999;
	animation: moneyFall 2s ease-in forwards;
}

@keyframes moneyFall {
	0% {
		transform: translateY(0) rotate(0deg);
		opacity: 1;
	}
	100% {
		transform: translateY(100vh) rotate(360deg);
		opacity: 0;
	}
}
